    {
        p               1e-3;
        U               1e-4;
        h               1e-3;
        "(k|epsilon)"   1e-3;
    }
}

relaxationFactors
{
    fields
    {
        p               1;
    }

    equations
    {
        p               1;
        U               0.9;
        h               0.9;
        k               0.9;
        epsilon         0.9;
    }
}

